/*****************************************
 * Calculate Percentage of Mandate Amount
 * 
 * by Cinthia Romero
 * modified by Elmer Orihuela
 * modified by Adriana Centellas
 ****************************************/
var initialAmount = this._parent.PE_MANDATE_TOTAL_ACTUAL_ALLOCATION;
var mandateAmount = this.PE_MANDATE_ACTUAL_ALLOCATION;
var percentageValue = 0;
if (initialAmount != "" && initialAmount != undefined && initialAmount != null && initialAmount != 0 && mandateAmount != "" && mandateAmount != undefined && mandateAmount != null) {
    percentageValue = (mandateAmount * 100) / initialAmount;
}
return percentageValue;

let mandateAmount = this.PE_MANDATE_AMOUNT;
let mandateActual = this.PE_MANDATE_ACTUAL_ALLOCATION;
let alertMessage = '';
let percent = 0.5;
let finalMandateAmount = mandateAmount + (mandateAmount * (percent/100)); 
if (mandateActual > finalMandateAmount) {
    alertMessage = 'Cannot be more than ' + percent + '% above '+ this.PE_MANDATE_AMOUNT.toLocaleString();
}
return alertMessage;
